const showToast = (message) => { const toast=document.querySelector('#toast'); toast.textContent=message; toast.classList.add('show'); setTimeout(()=>toast.classList.remove('show'),2200); };
function showLogin(){
  if(document.querySelector('.auth-screen')) return;
  const isLocal=['localhost','127.0.0.1'].includes(location.hostname);
  const localHint=isLocal?'<small>本地测试：admin / admin123<br>参保单位：enterprise / enterprise123</small>':'<small>请使用云端部署时配置的安全账号密码</small>';
  const el=document.createElement('div'); el.className='auth-screen'; el.innerHTML=`<div class="auth-card"><div class="auth-logo">响</div><h1>响帮帮保经云</h1><p>请选择登录门户</p><form><label>登录门户<select name="portal"><option value="admin">总后台 · 平台运营</option><option value="enterprise">参保单位后台 · 企业 / HR</option></select></label><label>账号<input name="username" value="${isLocal?'admin':''}" autocomplete="username"></label><label>密码<input name="password" type="password" value="${isLocal?'admin123':''}" autocomplete="current-password"></label><button class="primary full">登录系统 →</button>${localHint}<div class="auth-error"></div></form></div>`;
  document.body.appendChild(el); el.querySelector('form').addEventListener('submit',async(e)=>{e.preventDefault(); const form=new FormData(e.currentTarget); const btn=e.currentTarget.querySelector('button'); btn.disabled=true; try{const result=await api('/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:form.get('username'),password:form.get('password'),portal:form.get('portal')})}); localStorage.setItem('xbb-auth-token',result.access_token); el.remove(); loadDashboard(); applyPortal();}catch(err){el.querySelector('.auth-error').textContent=err.message;btn.disabled=false;}});
}
async function loadDashboard(){ try { const data=await api('/dashboard'),values=document.querySelectorAll('#page-home .stat>b'),labels=document.querySelectorAll('#page-home .stat .stat-head span'); if(labels[0])labels[0].textContent=data.portal==='enterprise'?'当前投保单位':'合作企业';if(values[0]) values[0].textContent=data.enterprises;if(labels[1])labels[1].textContent='账户余额';if(values[1])values[1].textContent=`¥ ${Number(data.premium_balance||0).toFixed(2)}`;if(labels[2])labels[2].textContent='待处理事项';if(values[2])values[2].textContent=Number(data.pending_people||0)+Number(data.claims_open||0)+Number(data.balance_alerts?.length||0);if(labels[3])labels[3].textContent='参保人员';if(values[3]) values[3].textContent=data.people;const kicker=document.querySelector('#page-home .welcome .kicker');if(kicker)kicker.textContent=new Intl.DateTimeFormat('zh-CN',{dateStyle:'full'}).format(new Date()); } catch(err) { if(err.message.includes('登录')) showLogin();else showToast(`工作台加载失败：${err.message}`); } }
async function applyPortal(){ try { const me=await api('/auth/me'); document.body.dataset.portal=me.role; const isEnterprise=me.role==='enterprise'; document.querySelector('.account-card b').textContent=me.name; document.querySelector('.account-card small').textContent=isEnterprise?'参保单位账户':'平台运营账户'; document.querySelector('.top-user>span:not(.avatar)').textContent=me.name; if(isEnterprise){ ['insurers','insurance','promotion','agents'].forEach((key)=>document.querySelector(`[data-page="${key}"]`)?.classList.add('role-hidden')); document.querySelector('.brand>span:last-child').textContent='响帮帮保经云 · 参保单位'; } } catch(err){} }
const esc=(value)=>String(value??'').replace(/[&<>"']/g,(c)=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
let editingPlanId=null;
async function loadPlans(){
  const tbody=document.querySelector('#plan-rows'); if(!tbody) return;
  try { const plans=await api('/plans'); document.querySelector('#plan-count').textContent=`共 ${plans.length} 条`; tbody.innerHTML=plans.map((p)=>`<tr data-plan-id="${p.id}"><td>${esc(p.insurer)}</td><td><b>${esc(p.name)}</b></td><td>${esc(p.coverage)}</td><td>¥ ${Number(p.price).toFixed(2)}</td><td>${(Number(p.commission_rate)*100).toFixed(1)}%</td><td>${esc(p.payment_mode)}</td><td>${p.billing_mode==='daily'?'按天':'按月'}</td><td>${p.effective_mode==='immediate'?'即时生效':'次日生效'}</td><td><label class="status ${p.status==='active'?'on':'off'}">● ${p.status==='active'?'启用':'已暂停'}</label></td><td><a data-plan-action="detail">查看</a><a data-plan-action="edit">修改</a><a data-plan-action="toggle">${p.status==='active'?'暂停':'恢复'}</a><a data-plan-action="delete" class="danger-link">删除</a></td></tr>`).join('')||'<tr><td colspan="10" class="loading-cell">暂无方案，请先录入</td></tr>'; tbody.querySelectorAll('[data-plan-action]').forEach((a)=>a.addEventListener('click',async()=>{const row=a.closest('tr'), id=row.dataset.planId, plan=plans.find(x=>String(x.id)===id); if(a.dataset.planAction==='detail'){detail('方案详情',`<p>保险公司：${esc(plan.insurer)}</p><p>方案名称：${esc(plan.name)}</p><p>计费模式：${plan.billing_mode==='daily'?'按天':'按月'}</p><p>生效模式：${plan.effective_mode==='immediate'?'即时生效':'次日生效'}</p><p>基础价格：¥ ${Number(plan.price).toFixed(2)}</p>`);} else if(a.dataset.planAction==='edit'){editingPlanId=plan.id;const form=document.querySelector('#plan-form');form.querySelector('[name="insurer"]').value=plan.insurer;form.querySelector('[name="name"]').value=plan.name;form.querySelector('[name="coverage"]').value=plan.coverage;form.querySelector('[name="occupation_classes"]').value=plan.occupation_classes;form.querySelector('[name="price"]').value=plan.price;form.querySelector('[name="commission_rate"]').value=plan.commission_rate;form.querySelector('[name="payment_mode"]').value=plan.payment_mode;form.querySelector('[name="billing_mode"]').value=plan.billing_mode||'monthly';form.querySelector('[name="effective_mode"]').value=plan.effective_mode||'next_day';form.querySelector('button[type="submit"]').textContent='保存修改';document.querySelector('#plan-form').scrollIntoView({behavior:'smooth'});showToast('已回填方案，可修改后保存');} else if(a.dataset.planAction==='delete'){if(!confirm(`确定删除“${plan.name}”？已被参保人员或保单使用的方案无法删除。`))return;try{await api(`/plans/${id}`,{method:'DELETE'});showToast('方案已删除');loadPlans();}catch(err){showToast(`删除失败：${err.message}`);}} else if(confirm(`确认${plan.status==='active'?'暂停':'恢复'}“${plan.name}”？`)){await api(`/plans/${id}/status?status=${plan.status==='active'?'paused':'active'}`,{method:'PATCH'});showToast('方案状态已更新');loadPlans();}})); } catch(err){ tbody.innerHTML=`<tr><td colspan="10" class="loading-cell">${esc(err.message)}</td></tr>`; }
}

function go(page){
  document.querySelectorAll('.page').forEach((el)=>el.classList.add('hidden'));
  const target=document.querySelector(`#page-${page}`) || document.querySelector('#page-generic');
  target.classList.remove('hidden');
  if(!document.querySelector(`#page-${page}`) || page==='insurance' || page==='policy' || page==='claims' || page==='team' || page==='promotion' || page==='exports' || page==='dispatch' || page==='screen') { genericTitle.textContent=pages[page] || page; if(page==='team') renderEnterprises(); else if(page==='insurance') renderProducts(); else if(page==='policy') renderPolicies(); else if(page==='claims') renderClaims(); else if(page==='promotion') renderPromotion(); else if(page==='exports') renderEnrollmentCenter(); else if(page==='dispatch') renderPositions(); else if(page==='screen') renderDataScreen(); else renderGeneric(page); }
  parent.textContent=page==='home'?'工作台':'业务管理'; current.textContent=pages[page] || page;
  document.querySelectorAll('.side-nav a').forEach((link)=>link.classList.toggle('active',link.dataset.page===page));
  location.hash=page;
}
function renderGeneric(page){if(page==='agents'){renderAgents();return;}const data=moduleData[page];const root=document.querySelector('#page-generic');if(!data)return;const count=data.rows.length;root.innerHTML=`<div class="page-heading"><div><div class="kicker">${data.k}</div><h1 id="generic-title">${pages[page]}</h1><p>${data.desc}</p></div><button class="primary generic-add">＋ 新增</button></div><div class="module-stats"><div><span>业务总量</span><b>${count*64}</b></div><div><span>待处理</span><b>${page==='message'?3:8}</b></div><div><span>本月增长</span><b class="up">↑ 12.6%</b></div></div><div class="filterbar"><input placeholder="搜索${pages[page]}"/><select><option>全部状态</option><option>正常/已通过</option><option>待处理</option><option>已暂停</option></select><button class="outline generic-filter">筛选</button><button class="outline generic-export">导出数据</button></div><div class="panel table-panel"><div class="table-caption"><b>${pages[page]} <small>共 ${count} 条记录</small></b><span>数据实时同步</span></div><table><thead><tr>${data.cols.map(c=>`<th>${c}</th>`).join('')}<th>操作</th></tr></thead><tbody>${data.rows.map(row=>`<tr>${row.map(c=>`<td>${c}</td>`).join('')}<td><a class="generic-view">查看</a><a class="generic-edit">编辑</a></td></tr>`).join('')}</tbody></table><div class="list-footer generic-pagination"><span>共 ${count} 条记录 · 当前第 1 页</span><div><button>‹</button><button class="active">1</button><button>›</button></div><label>每页 10 条</label></div></div></div>`;root.querySelector('.generic-add').addEventListener('click',()=>detail(`新增${pages[page]}`,`<p>新增表单已准备就绪，提交后会进入人工审核并写入审计日志。</p><p>当前模块：${pages[page]}</p>`));root.querySelector('.generic-filter').addEventListener('click',()=>showToast('筛选条件已应用'));root.querySelector('.generic-export').addEventListener('click',()=>exportGeneric(data));root.querySelectorAll('.generic-view').forEach((a)=>a.addEventListener('click',()=>detail(`${pages[page]}详情`,`<p>记录已加载，可查看完整字段、业务关联和操作日志。</p><p>该操作不会修改数据。</p>`)));root.querySelectorAll('.generic-edit').forEach((a)=>a.addEventListener('click',()=>showToast('已打开编辑流程')));root.querySelectorAll('.generic-pagination button').forEach((b)=>b.addEventListener('click',()=>{if(b.textContent==='1')return;showToast('当前示例列表已展示全部记录');}));}
async function renderAgents(){const root=document.querySelector('#page-generic');root.innerHTML='<div class="page-heading"><div><div class="kicker">SALESPERSON MANAGEMENT</div><h1 id="generic-title">业务员管理</h1><p>账号、对接企业和产品佣金关系统一管理</p></div><button class="primary" id="agent-add">＋ 新增业务员</button></div><div class="module-stats"><div><span>业务员总数</span><b id="agent-total">0</b></div><div><span>对接产品关系数</span><b id="agent-product-total">0</b></div><div><span>预计佣金合计</span><b class="up" id="agent-commission-total">¥ 0.00</b></div></div><div class="panel plan-entry"><form id="agent-form" class="form-grid"><label>姓名<input name="name" required placeholder="业务员姓名"></label><label>登录账号<input name="username" required placeholder="登录账号"></label><label>初始密码<input name="password" required value="123456"></label><label>手机号码<input name="phone" placeholder="手机号"></label><div class="form-actions"><button class="primary" type="submit">保存业务员</button></div></form><p class="muted" style="margin-top:12px">佣金比例不在业务员账号上设置：同一业务员对接的不同企业、不同产品可分别设置各自的佣金比例，请在下方列表中点击「关联业务」逐一配置。</p></div><div class="panel table-panel"><div class="table-caption"><b>业务员列表 <small id="agent-count">加载中</small></b><span>仅总后台可操作</span></div><table><thead><tr><th>姓名</th><th>账号</th><th>手机</th><th>对接企业</th><th>对接产品</th><th>预计佣金</th><th>状态</th><th>操作</th></tr></thead><tbody id="agent-rows"><tr><td colspan="8" class="loading-cell">正在加载…</td></tr></tbody></table><div class="list-footer"><span id="agent-pagination">共 0 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>';const form=root.querySelector('#agent-form');form.addEventListener('submit',async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(form));try{await api('/agents',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});form.reset();showToast('业务员已创建');renderAgents();}catch(err){showToast(`保存失败：${err.message}`);}});root.querySelector('#agent-add').addEventListener('click',()=>form.querySelector('[name="name"]').focus());try{const agents=await api('/agents');root.querySelector('#agent-total').textContent=agents.length;root.querySelector('#agent-count').textContent=`共 ${agents.length} 条记录`;root.querySelector('#agent-product-total').textContent=agents.reduce((n,a)=>n+Number(a.product_count||0),0);root.querySelector('#agent-commission-total').textContent=`¥ ${agents.reduce((n,a)=>n+Number(a.total_commission||0),0).toFixed(2)}`;root.querySelector('#agent-rows').innerHTML=agents.map(a=>`<tr><td><b>${esc(a.name)}</b></td><td>${esc(a.username)}</td><td>${esc(a.phone||'—')}</td><td>${a.enterprise_count||0}</td><td>${a.product_count||0}</td><td>¥ ${Number(a.total_commission||0).toFixed(2)}</td><td><label class="status ${a.active?'on':'off'}">● ${a.active?'正常':'已停用'}</label></td><td><a data-agent-link="${a.id}">关联业务</a><a data-agent-view="${a.id}">查看业务</a><a data-agent-toggle="${a.id}">${a.active?'停用':'启用'}</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无业务员，请先新增</td></tr>';root.querySelectorAll('[data-agent-toggle]').forEach(a=>a.addEventListener('click',async()=>{const active=a.textContent==='停用';await api(`/agents/${a.dataset.agentToggle}/status?status=${active?'inactive':'active'}`,{method:'PATCH'});showToast('业务员状态已更新');renderAgents();}));root.querySelectorAll('[data-agent-link]').forEach(a=>a.addEventListener('click',()=>openPricingBusinessForm(null,Number(a.dataset.agentLink))));root.querySelectorAll('[data-agent-view]').forEach(a=>a.addEventListener('click',()=>openAgentCommissionList(Number(a.dataset.agentView))));}catch(err){showToast(err.message);}}
function exportGeneric(data){const csv=[data.cols.join(','),...data.rows.map(r=>r.map(x=>`"${x}"`).join(','))].join('\n');const url=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv'}));const a=document.createElement('a');a.href=url;a.download='响帮帮保经云-'+Date.now()+'.csv';a.click();URL.revokeObjectURL(url);showToast('数据已导出');}
