const launchParams=new URLSearchParams(location.search);
if(authToken() && launchParams.get('autologin')!=='1' && launchParams.get('portal')!=='enterprise') { loadDashboard(); applyPortal(); } else if(launchParams.get('autologin')==='1' && ['localhost','127.0.0.1'].includes(location.hostname)) {
  const enterprisePortal=launchParams.get('portal')==='enterprise';
  api('/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:enterprisePortal?'enterprise':'admin',password:enterprisePortal?'enterprise123':'admin123',portal:enterprisePortal?'enterprise':'admin'})}).then((result)=>{localStorage.setItem('xbb-auth-token',result.access_token);loadDashboard();applyPortal();}).catch(()=>showLogin());
} else showLogin();

// 统一交互：列表筛选、导出、详情、状态操作、分页、快捷入口和确认提示
function detail(title, body){
  const modal=document.createElement('div'); modal.className='modal show'; modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>${title}</h2><div class="detail-content">${body}</div><button class="primary full modal-close-action">知道了</button></div>`;
  document.body.appendChild(modal); modal.querySelectorAll('.modal-close,.modal-close-action').forEach((b)=>b.addEventListener('click',()=>modal.remove()));
}
document.querySelector('.icon-btn:not(.notification)')?.addEventListener('click',()=>{const q=prompt('搜索系统功能或企业名称'); if(q) showToast(`正在搜索：${q}`);});
document.querySelector('.notification')?.addEventListener('click',()=>go('message'));
document.querySelectorAll('.chart-panel select').forEach((select)=>select.addEventListener('change',()=>showToast(`已切换为：${select.value}`)));
const workerInput=document.querySelector('#page-workers .filterbar input');
const workerRows=[...document.querySelectorAll('#page-workers tbody tr')];
function filterWorkers(){const q=(workerInput?.value||'').toLowerCase(); const status=document.querySelector('#page-workers .filterbar select')?.value||'全部状态'; workerRows.forEach(row=>{const text=row.textContent.toLowerCase(); const statusMatch=status==='全部状态'||(status==='在保'&&text.includes('在保'))||(status==='待审核'&&text.includes('待审核'))||(status==='已离职'&&text.includes('离职')); row.style.display=text.includes(q)&&statusMatch?'':'none';});}
document.querySelector('#page-workers .filterbar .outline')?.addEventListener('click',()=>{filterWorkers();showToast('筛选条件已应用')}); workerInput?.addEventListener('keydown',(e)=>{if(e.key==='Enter')filterWorkers()});
document.querySelector('#page-workers .filterbar select')?.addEventListener('change',filterWorkers);
document.querySelector('#page-workers thead input')?.addEventListener('change',(e)=>document.querySelectorAll('#page-workers tbody input[type=checkbox]').forEach((x)=>x.checked=e.target.checked));
document.querySelector('#page-workers .filterbar .outline:last-child')?.addEventListener('click',()=>{const rows=workerRows.filter(r=>r.style.display!=='none'); const csv=['姓名,手机号,劳动关系单位,保险方案,状态,加入时间',...rows.map(r=>[...r.querySelectorAll('td')].slice(1,6).map(x=>`"${x.innerText.replaceAll('"','""')}"`).join(','))].join('\n'); const url=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv'})); const a=document.createElement('a'); a.href=url; a.download='投保人员名单.csv'; a.click(); URL.revokeObjectURL(url); showToast('员工名单已导出');});
document.querySelectorAll('#page-workers tbody td:last-child a').forEach((a,i)=>a.addEventListener('click',()=>{const row=a.closest('tr'); const person=row.querySelector('.person b').textContent; if(a.textContent==='查看') detail(`投保人员 · ${person}`,`<p>当前状态：<b class="status on">在保</b></p><p>劳动关系单位：${row.children[2].textContent}</p><p>保险方案：${row.children[3].textContent}</p><p>加入时间：${row.children[5].textContent}</p>`); else {showToast(`已进入 ${person} 的编辑模式`); row.querySelector('.person b').style.color='var(--blue)';}}));
document.querySelectorAll('.pagination button').forEach((b)=>b.addEventListener('click',()=>{if(!b.textContent.includes('…')){document.querySelectorAll('.pagination button').forEach(x=>x.classList.remove('active'));b.classList.add('active');showToast(`已切换到第 ${b.textContent} 页`);}}));
document.querySelectorAll('#page-insurance .plan button').forEach((b)=>b.addEventListener('click',()=>detail('保险方案详情',`<p>方案：团体意外险 · 标准版</p><p>保障范围：意外身故 / 伤残、意外医疗、快速理赔</p><p>适用职业：1-4 类</p><p>操作将生成待审核的开通申请，确认后由运营人员复核。</p>`)));
document.querySelectorAll('.todo-item').forEach((item)=>item.addEventListener('click',()=>{const text=item.querySelector('b')?.textContent||''; if(text.includes('保单'))go('policy'); else if(text.includes('员工'))go('workers'); else if(text.includes('发票'))go('billing'); else showToast('该事项已记录');}));
document.querySelectorAll('.placeholder .outline').forEach((b)=>b.addEventListener('click',()=>detail('操作指引','<p>先创建或导入业务数据，再使用筛选、批量操作、导出和详情功能。所有高风险操作都会要求二次确认，并写入审计日志。</p>')));
document.querySelectorAll('.page-heading .primary').forEach((b)=>b.addEventListener('click',()=>{if(b.closest('#page-workers'))document.querySelector('[data-action="add-worker"]').click();else showToast('新增流程已打开，请按页面提示完成填写');}));
document.querySelector('[data-action="new-plan"]')?.addEventListener('click',()=>document.querySelector('#plan-form input[name="insurer"]')?.focus());
document.querySelector('#plan-form')?.addEventListener('submit',async(e)=>{e.preventDefault();if(e.currentTarget.dataset.saving==='1')return;const form=e.currentTarget;const submit=form.querySelector('button[type="submit"]');const original=submit.textContent;const wasEditing=Boolean(editingPlanId);form.dataset.saving='1';submit.disabled=true;submit.textContent='保存中…';const values=new FormData(form);const data=Object.fromEntries(values.entries());data.price=Number(data.price);data.commission_rate=Number(data.commission_rate);try{const saved=await api(wasEditing?`/plans/${editingPlanId}`:'/plans',{method:wasEditing?'PATCH':'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});form.reset();editingPlanId=null;showToast(`方案“${saved.name}”已${wasEditing?'修改':'保存'}`);submit.textContent='保存方案';await loadPlans();document.querySelector('#plan-rows')?.closest('.plan-table')?.scrollIntoView({behavior:'smooth',block:'start'});}catch(err){showToast(`保存失败：${err.message}`);}finally{form.dataset.saving='0';submit.disabled=false;if(!editingPlanId&&!wasEditing)submit.textContent=original;}});
document.querySelector('[data-page="insurers"]')?.addEventListener('click',()=>setTimeout(loadPlans,0));
if(authToken()) loadPlans();
document.querySelectorAll('#page-workers tbody tr td:last-child').forEach((cell)=>{if(!cell.querySelector('[data-worker-action]')){const a=document.createElement('a');a.href='#';a.dataset.workerAction='toggle';a.textContent='停保';cell.appendChild(a);}});
document.addEventListener('click',(e)=>{const action=e.target.closest('[data-worker-action]');if(!action)return;e.preventDefault();const row=action.closest('tr');const name=row?.querySelector('.person b')?.textContent||'员工';if(confirm(`确认对${name}执行停保？`)){action.textContent=action.textContent==='停保'?'恢复':'停保';showToast(`${name}状态已更新`);}},true);
async function openAgentCommissionList(agentId){try{const [agents,rows]=await Promise.all([api('/agents'),api(`/agents/${agentId}/commissions`)]);const agent=agents.find(x=>x.id===agentId);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>${esc(agent?.name||'')} 的对接业务</h2><p>同一业务员对接的企业使用不同产品可各自设置佣金</p><div class="detail-content">${rows.length?rows.map(x=>`<p><b>${esc(x.enterprise_name)}</b> · ${esc(x.insurer)} ${esc(x.plan_name)} · ${x.mode==='rebate'?`返佣 ${(Number(x.rate)*100).toFixed(1)}%`:'按销售价加价'} · 在保 ${x.insured_count} 人 · 预计佣金 ¥${Number(x.agent_commission_total).toFixed(2)} · ${x.status==='active'?'推广中':'已暂停'} <a data-edit-id="${x.id}">编辑</a></p>`).join(''):'<p>暂无对接业务，请点击「关联业务」添加。</p>'}</div><button class="primary full" id="agent-commission-close">关闭</button></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('#agent-commission-close').onclick=()=>modal.remove();modal.querySelectorAll('[data-edit-id]').forEach(a=>a.addEventListener('click',()=>{const item=rows.find(r=>r.id===Number(a.dataset.editId));if(item){modal.remove();openPricingBusinessForm(item);}}));}catch(err){showToast(err.message);}}
const enterpriseFormObserver=new MutationObserver(()=>{document.querySelectorAll('.enterprise-form').forEach(async(form)=>{if(form.querySelector('[name="agent_id"]'))return;const label=document.createElement('label');label.textContent='负责业务员';const select=document.createElement('select');select.name='agent_id';select.innerHTML='<option value="">请选择业务员</option>';try{const agents=await api('/agents');agents.forEach(a=>{const o=document.createElement('option');o.value=a.id;o.textContent=a.name;select.appendChild(o);});}catch(err){}label.appendChild(select);form.insertBefore(label,form.querySelector('button[type="submit"]'));});});enterpriseFormObserver.observe(document.body,{childList:true});
document.addEventListener('submit',async(e)=>{const form=e.target;if(!form.classList.contains('enterprise-form'))return;e.preventDefault();e.stopImmediatePropagation();const data=Object.fromEntries(new FormData(form));data.agent_id=data.agent_id?Number(data.agent_id):null;const btn=form.querySelector('button[type="submit"]');btn.disabled=true;try{const saved=await api('/enterprises',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});form.closest('.modal')?.remove();showToast(`投保单位“${saved.name}”已创建`);renderEnterprises();}catch(err){form.querySelector('.auth-error').textContent=err.message;btn.disabled=false;}},true);
const editEnterpriseObserver=new MutationObserver(async()=>{const heading=[...document.querySelectorAll('.modal-box h2')].find(x=>x.textContent.includes('编辑投保单位'));if(!heading)return;const form=heading.closest('.modal-box')?.querySelector('form');if(!form||form.querySelector('[name="agent_id"]'))return;const label=document.createElement('label');label.textContent='负责业务员';const select=document.createElement('select');select.name='agent_id';select.innerHTML='<option value="">暂不指定</option>';try{const agents=await api('/agents');agents.forEach(x=>{const o=document.createElement('option');o.value=x.id;o.textContent=x.name;select.appendChild(o);});}catch(err){}label.appendChild(select);form.insertBefore(label,form.querySelector('button[type="submit"]'));});editEnterpriseObserver.observe(document.body,{childList:true});
document.addEventListener('submit',async(e)=>{const heading=e.target.closest('.modal-box')?.querySelector('h2');if(!heading||!heading.textContent.includes('编辑投保单位'))return;e.preventDefault();e.stopImmediatePropagation();const data=Object.fromEntries(new FormData(e.target));data.agent_id=data.agent_id?Number(data.agent_id):null;try{const saved=await api(`/enterprises/${e.target.dataset.enterpriseId||''}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});e.target.closest('.modal')?.remove();showToast(`单位“${saved.name}”已修改`);renderEnterprises();}catch(err){e.target.querySelector('.auth-error').textContent=err.message;}},true);
const editIdObserver=new MutationObserver(async()=>{for(const form of document.querySelectorAll('.modal-box form')){if(!form.dataset.enterpriseId&&form.closest('.modal-box')?.querySelector('h2')?.textContent.includes('编辑投保单位')){try{const all=await api('/enterprises');form.dataset.enterpriseId=all.find(x=>x.name===form.querySelector('[name="name"]')?.value)?.id||'';}catch(err){}}}});editIdObserver.observe(document.body,{childList:true});
const enterpriseColumnObserver=new MutationObserver(async()=>{const rows=document.querySelectorAll('#enterprise-rows tr');const table=document.querySelector('#page-generic .table-panel table');if(!rows.length||!table||rows[0].querySelector('.loading-cell'))return;const head=table.querySelector('thead tr');if(!head.querySelector('[data-agent-column]')){const th=document.createElement('th');th.dataset.agentColumn='1';th.textContent='负责业务员';head.insertBefore(th,head.lastElementChild);}let items=[];try{items=await api('/enterprises')}catch(err){}rows.forEach((row,i)=>{if(row.querySelector('[data-agent-cell]'))return;const td=document.createElement('td');td.dataset.agentCell='1';td.textContent=items[i]?.agent_name||'未分配';row.insertBefore(td,row.lastElementChild);});});enterpriseColumnObserver.observe(document.body,{childList:true});
