// v3.4 工伤理赔三端闭环
const claimTransitions={reported:['collecting'],collecting:['submitted'],submitted:['insurer_review','supplement'],insurer_review:['supplement','approved','rejected'],supplement:['submitted','insurer_review'],approved:['paid'],paid:['closed'],rejected:['closed'],closed:[]};
const claimRiskText={normal:'正常',attention:'关注',high:'高风险'};

async function renderClaims(){
  const root=document.querySelector('#page-generic');
  try {
    const [me,rows]=await Promise.all([api('/auth/me'),api('/claims')]);
    const isEnterprise=me.role==='enterprise';
    root.innerHTML=`<div class="page-heading"><div><div class="kicker">WORK INJURY CLAIMS</div><h1>${isEnterprise?'工伤理赔':'理赔案件工作台'}</h1><p>${isEnterprise?'工伤报案、材料上传、补件和赔付结果跟踪':'全平台案件、材料、风险、SLA、核赔和赔付闭环'}</p></div>${isEnterprise?'<button class="primary" id="claim-add">＋ 发起工伤报案</button>':''}</div><div class="module-stats"><div><span>案件总数</span><b>${rows.length}</b></div><div><span>处理中</span><b>${rows.filter(x=>!['paid','rejected','closed'].includes(x.status)).length}</b></div><div><span>待补材料</span><b>${rows.filter(x=>x.status==='supplement'||x.missing_count>0).length}</b></div><div><span>逾期 / 高风险</span><b class="${rows.some(x=>x.calculated_risk==='high')?'danger-text':''}">${rows.filter(x=>x.calculated_risk==='high').length}</b></div></div><div class="filterbar"><input id="claim-search" placeholder="搜索案件号、员工、单位"><select id="claim-status"><option value="">全部节点</option>${Object.entries(claimStatusText).map(([key,label])=>`<option value="${key}">${label}</option>`).join('')}</select><select id="claim-risk"><option value="">全部风险</option><option value="normal">正常</option><option value="attention">需关注</option><option value="high">高风险</option></select><button class="outline" id="claim-filter">筛选</button></div><div class="panel table-panel"><div class="table-caption"><b>理赔案件 <small>共 ${rows.length} 件</small></b><span>状态只能按设计流程向前推进</span></div><table><thead><tr><th>案件号</th><th>单位 / 员工</th><th>出险信息</th><th>金额</th><th>材料</th><th>当前节点</th><th>负责人 / 时限</th><th>操作</th></tr></thead><tbody id="claim-rows">${rows.map(x=>`<tr data-claim-id="${x.id}"><td><b>${esc(x.claim_no)}</b><small>${new Date(x.created_at).toLocaleString()}</small></td><td>${esc(x.person_name)}<small>${esc(x.enterprise_name)} · ${esc(x.actual_employer_name||'—')}</small></td><td>${esc(x.accident_type)}<small>${esc(x.accident_at)} · ${esc(x.accident_place)}</small></td><td>申请 ¥${Number(x.amount||0).toFixed(2)}<small>核赔 ¥${Number(x.approved_amount||0).toFixed(2)}</small></td><td>${x.complete_percent}%<small class="${x.missing_count?'danger-text':''}">${x.missing_count?`缺 ${x.missing_count} 项`:'已齐全'}</small></td><td><label class="status ${['paid','closed','approved'].includes(x.status)?'on':x.status==='rejected'?'off':'wait'}">● ${claimStatusText[x.status]||x.status}</label><small class="${x.calculated_risk==='high'?'danger-text':''}">${claimRiskText[x.calculated_risk]||x.calculated_risk}</small></td><td>${esc(x.current_handler||'待分配')}<small class="${x.deadline_overdue||x.sla_overdue?'danger-text':''}">${x.deadline_days===null?'未设置时限':x.deadline_days<0?`工伤认定已超 ${Math.abs(x.deadline_days)} 天`:`工伤认定剩 ${x.deadline_days} 天`}</small></td><td><a data-claim-detail="${x.id}">案件工作台</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无理赔案件</td></tr>'}</tbody></table></div>`;
    root.querySelector('#claim-add')?.addEventListener('click',openClaimCreate);
    const applyFilter=()=>{const q=root.querySelector('#claim-search').value.toLowerCase(),status=root.querySelector('#claim-status').value,risk=root.querySelector('#claim-risk').value;root.querySelectorAll('#claim-rows tr[data-claim-id]').forEach(row=>{const item=rows.find(x=>x.id===Number(row.dataset.claimId));row.style.display=row.textContent.toLowerCase().includes(q)&&(!status||item.status===status)&&(!risk||item.calculated_risk===risk)?'':'none';});};
    root.querySelector('#claim-filter').onclick=applyFilter;root.querySelector('#claim-search').onkeydown=e=>{if(e.key==='Enter')applyFilter();};
    root.querySelectorAll('[data-claim-detail]').forEach(a=>a.onclick=()=>openClaimWorkbench(Number(a.dataset.claimDetail)));
  } catch(err){showToast(err.message);}
}

